import warnings

def deprecated(message):
    """
    फ़ंक्शन और विधियों को अप्रचलित घोषित करने के लिए डेकोरेटर।

    ::

        @deprecated("'foo' को 'bar' के पक्ष में अप्रचलित घोषित किया गया है")
        def foo(x):
            pass
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            warnings.warn(
                f"{func.__name__} is deprecated: {message}",
                category=DeprecationWarning,
                stacklevel=2
            )
            return func(*args, **kwargs)
        return wrapper
    return decorator

def parse_version(s: str) -> tuple[int, ...]:
    """
    साधारण (poor man's) वर्शन तुलना।
    """
    return tuple(map(int, s.split('.')))

def cached(cache, key=hashkey, lock=None):
    """
    यह एक डेकोरेटर है जो किसी फ़ंक्शन को एक मेमोराइज़िंग कॉल करने योग्य (memoizing callable) के साथ रैप करता है, जो परिणामों को कैश में सहेजता है।
    """
    def decorator(func):
        def wrapper(*args, **kwargs):
            cache_key = key(*args, **kwargs)
            if cache_key in cache:
                return cache[cache_key]
            if lock:
                with lock:
                    if cache_key in cache:
                        return cache[cache_key]
                    result = func(*args, **kwargs)
                    cache[cache_key] = result
            else:
                result = func(*args, **kwargs)
                cache[cache_key] = result
            return result
        return wrapper
    return decorator

import time
from functools import wraps, lru_cache

def ttl_cache(maxsize=128, ttl=600, timer=time.monotonic, typed=False):
    """
    एक डेकोरेटर जो एक फ़ंक्शन को एक मेमोराइज़िंग कॉलेबल के साथ रैप करता है,
    जो `maxsize` तक के परिणामों को सेव करता है। यह एक Least Recently Used (LRU)
    एल्गोरिदम पर आधारित होता है और प्रत्येक आइटम के लिए एक समय-सीमा (Time-To-Live, TTL) 
    मान लागू करता है।
    """
    def decorator(func):
        @lru_cache(maxsize=maxsize, typed=typed)
        def cached_func(*args, **kwargs):
            return func(*args, **kwargs)

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = (args, frozenset(kwargs.items())) if typed else (args, tuple(kwargs.items()))
            if key in wrapper._cache:
                value, timestamp = wrapper._cache[key]
                if timer() - timestamp < ttl:
                    return value
            result = cached_func(*args, **kwargs)
            wrapper._cache[key] = (result, timer())
            return result

        wrapper._cache = {}
        return wrapper

    return decorator

from functools import wraps
from collections import OrderedDict

def mru_cache(maxsize=128, typed=False):
    def decorator(func):
        cache = OrderedDict()

        @wraps(func)
        def wrapper(*args, **kwargs):
            if typed:
                key = (args, tuple((k, type(v)) for k, v in sorted(kwargs.items())))
            else:
                key = (args, tuple(sorted(kwargs.items())))

            if key in cache:
                # Move the accessed key to the end to mark it as most recently used
                cache.move_to_end(key)
                return cache[key]

            result = func(*args, **kwargs)

            if len(cache) >= maxsize:
                # Remove the least recently used item
                cache.popitem(last=False)

            cache[key] = result
            return result

        return wrapper

    return decorator

def popitem(self):
    """
    पहले डाली गई `(key, value)` जोड़ी को हटाएं और लौटाएं।
    """
    if not self:
        raise KeyError("dictionary is empty")
    key = next(iter(self))
    value = self[key]
    del self[key]
    return (key, value)

def setdefault(self, key, default=None):
    """
    D.setdefault(k[, d]) -> D.get(k, d)
    साथ ही, यदि `k` (कुंजी) `D` (डिक्शनरी) में मौजूद नहीं है, तो `D[k] = d` सेट कर दिया जाता है।
    """
    if key not in self:
        self[key] = default
    return self.get(key, default)

def get(self, key, default=None):
    """
    D.get(k[, d]) -> D[k] यदि k D में है, तो D[k] लौटाया जाएगा, अन्यथा d। d का डिफ़ॉल्ट मान None है।
    """
    if key in self:
        return self[key]
    else:
        return default

def cachedmethod(cache, key=hashkey, lock=None):
    """
    यह डेकोरेटर एक क्लास या इंस्टेंस मेथड को एक मेमोराइज़िंग कॉल करने योग्य फ़ंक्शन के साथ रैप करता है, जो परिणामों को कैश में सहेजता है।
    """
    def decorator(method):
        def wrapper(self, *args, **kwargs):
            cache_key = key(self, *args, **kwargs)
            if cache_key in cache:
                return cache[cache_key]
            if lock:
                with lock:
                    if cache_key in cache:
                        return cache[cache_key]
                    result = method(self, *args, **kwargs)
                    cache[cache_key] = result
            else:
                result = method(self, *args, **kwargs)
                cache[cache_key] = result
            return result
        return wrapper
    return decorator

import os

def is_file_exist(file_name):
    """
    फ़ाइल नाम की जाँच करें कि वह मौजूद है या नहीं।  
    :param file_name: फ़ाइल का नाम।  
    :type file_name: str  
    :return: true लौटाएगा (यदि फ़ाइल मौजूद है), false लौटाएगा (यदि फ़ाइल मौजूद नहीं है या फ़ाइल नाम अमान्य है)।  
    :rtype: bool  
    """
    try:
        return os.path.isfile(file_name)
    except (TypeError, ValueError):
        return False

def minimalBases(classes):
    """
    आधार कक्षाओं (base classes) की सूची को उसके क्रमबद्ध न्यूनतम समकक्ष (ordered minimum equivalent) में घटाएं।
    """
    minimal = []
    for cls in classes:
        if not any(issubclass(cls, base) for base in minimal):
            minimal.append(cls)
    return minimal

