def difference(d1, d2, level=-1):
    """
    यह फ़ंक्शन एक डिक्शनरी लौटाता है जिसमें *d1* के वे आइटम्स शामिल होते हैं जो *d2* में नहीं हैं।

    *level* पुनरावृत्ति की अधिकतम गहराई निर्धारित करता है। अनंत पुनरावृत्ति के लिए,
    इसे -1 पर सेट करें। स्तर 1 के लिए,
    यदि कोई कुंजी *d1* और *d2* दोनों में मौजूद है, लेकिन उसके मान अलग-अलग हैं,
    तो उसे अंतर में शामिल किया जाता है।
    अधिक जानकारी के लिए :func:`intersection` देखें।

    *d1* और *d2* अपरिवर्तित रहते हैं। हालाँकि, *d1* या इसके कुछ
    उपशब्दकोश सीधे लौटाए जा सकते हैं।
    जब उचित हो तो परिणाम की एक गहरी प्रतिलिपि बनाएँ।

    ..versionadded::0.5
    कीवर्ड तर्क *level* जोड़ें।
    """
    if level == 0:
        return {}

    diff = {}
    for key in d1:
        if key not in d2:
            diff[key] = d1[key]
        elif isinstance(d1[key], dict) and isinstance(d2[key], dict):
            if level != 1:
                sub_diff = difference(d1[key], d2[key], level - 1 if level != -1 else -1)
                if sub_diff:
                    diff[key] = sub_diff
        elif d1[key] != d2[key]:
            diff[key] = d1[key]

    return diff

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    यह फ़ंक्शन :func:``generate_default_observer_schema_list`` के साथ मिलकर पुनरावृत्त रूप से (recursively) कॉल किया जाता है ताकि किसी Kubernetes संसाधन (resource) के एक भाग से डिफ़ॉल्ट ``observer_schema`` का हिस्सा उत्पन्न किया जा सके, जिसे क्रमशः ``manifest_dict`` या ``manifest_list`` द्वारा परिभाषित किया गया है।

    आर्ग्युमेंट्स (Args):
    - manifest_dict (dict): आंशिक Kubernetes संसाधन (Partial Kubernetes resources)।
    - first_level (bool, optional): यदि True है, तो यह इंगित करता है कि डिक्शनरी Kubernetes संसाधन के पूरे observer schema का प्रतिनिधित्व करती है।

    रिटर्न्स (Returns):
    - dict: उत्पन्न आंशिक observer_schema (Generated partial observer_schema)।

    यह फ़ंक्शन ``manifest_dict`` से एक नई डिक्शनरी बनाता है और सभी non-list और non-dict मानों को ``None`` से बदल देता है।

    यदि यह ``first_level`` डिक्शनरी है (यानी किसी संसाधन के लिए पूरा ``observer_schema``), तो पहचानने वाले फ़ील्ड्स (identifying fields) के मान ``manifest`` फ़ाइल से कॉपी किए जाते हैं।
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            observer_schema[key] = []
            for item in value:
                if isinstance(item, dict):
                    observer_schema[key].append(generate_default_observer_schema_dict(item))
                else:
                    observer_schema[key].append(None)
        else:
            if first_level and key in ['apiVersion', 'kind', 'metadata']:
                observer_schema[key] = value
            else:
                observer_schema[key] = None

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    साथ में :func:``update_last_applied_manifest_dict_from_resp``, यह फ़ंक्शन 
    पुनरावृत्त रूप से कॉल किया जाता है ताकि आंशिक ``last_applied_manifest`` को 
    आंशिक Kubernetes प्रतिक्रिया से अपडेट किया जा सके।

    आर्ग्युमेंट्स (Args):
        last_applied_manifest (list): आंशिक ``last_applied_manifest`` जो 
            अपडेट किया जा रहा है।
        observer_schema (list): आंशिक ``observer_schema``।
        response (list): Kubernetes API से प्राप्त आंशिक प्रतिक्रिया।

    यह फ़ंक्शन सभी देखे गए फ़ील्ड्स (observed fields) के माध्यम से जाता है और 
    यदि वे पहले से मौजूद नहीं हैं तो उनके मान को ``last_applied_manifest`` में 
    आरंभ (initialize) करता है।
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)
            else:
                last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
