        observer_schema (dict): The partial `observer_schema`.
        response (dict): The partial response from the Kubernetes API.

    Raises:
        KeyError: If the observed fields are not present in the Kubernetes response.

    This function iterates through all observed fields and initializes their values if they are not already present in `last_applied_manifest`.
    """
    for key, value in observer_schema.items():
        if key not in response:
            raise KeyError(f"Key '{key}' not found in the Kubernetes response.")

        if isinstance(value, dict):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[key], value, response[key]
            )
        else:
            last_applied_manifest[key] = response[key]

def generate_default_observer_schema(app):
    """
    प्रत्येक Kubernetes संसाधन के लिए डिफ़ॉल्ट ऑब्ज़र्वर स्कीमा उत्पन्न करें जो ``spec.manifest`` में मौजूद है और जिसके लिए कोई कस्टम ऑब्ज़र्वर स्कीमा निर्दिष्ट नहीं किया गया है।

    आर्ग्युमेंट्स:
        app (krake.data.kubernetes.Application): वह एप्लिकेशन जिसके लिए डिफ़ॉल्ट ऑब्ज़र्वर स्कीमा उत्पन्न करना है।
    """
    default_schema = {
        "type": "object",
        "properties": {
            "status": {
                "type": "object",
                "properties": {
                    "conditions": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "properties": {
                                "type": {"type": "string"},
                                "status": {"type": "string"},
                                "lastTransitionTime": {"type": "string"},
                                "reason": {"type": "string"},
                                "message": {"type": "string"}
                            },
                            "required": ["type", "status"]
                        }
                    }
                },
                "required": ["conditions"]
            }
        },
        "required": ["status"]
    }

    # Iterate over all resources in the application's manifest
    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema'):
            resource.observer_schema = default_schema

    return app

def format(
        self,
        sql: AnyStr,
        params: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:
    if isinstance(params, dict):
        # Convert named parameters to out-style
        out_params = {}
        for key, value in params.items():
            if isinstance(key, str):
                out_params[f":{key}"] = value
            else:
                out_params[f":{key}"] = value
        formatted_sql = sql
        for key, value in params.items():
            if isinstance(key, str):
                formatted_sql = formatted_sql.replace(f":{key}", "?")
            else:
                formatted_sql = formatted_sql.replace(f":{key}", "?")
        return formatted_sql, out_params
    elif isinstance(params, (list, tuple)):
        # Convert positional parameters to out-style
        out_params = list(params)
        formatted_sql = sql
        for i in range(len(params)):
            formatted_sql = formatted_sql.replace(f"?", "?", 1)
        return formatted_sql, out_params
    else:
        raise TypeError("params must be a dict, list, or tuple")

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    formatted_sql = sql
    formatted_params = []

    for params in many_params:
        if isinstance(params, dict):
            # Handle named parameters
            formatted_params.append(params)
        elif isinstance(params, (list, tuple)):
            # Handle ordinal parameters
            formatted_params.append(list(params))
        else:
            raise TypeError("Parameters must be either a dictionary or a sequence.")

    return formatted_sql, formatted_params

import os
import re

class OCFLValidator:
    def validate(self, path):
        """
        पथ या pyfs रूट पर OCFL ऑब्जेक्ट को मान्य करें।

        यदि मान्य है (चेतावनियाँ स्वीकार्य हैं), तो True लौटाता है, अन्यथा False।
        """
        if not os.path.exists(path):
            return False

        # Check for the presence of required OCFL files and directories
        required_files = ['inventory.json', 'inventory.json.sha512']
        required_dirs = ['v1']

        for file in required_files:
            if not os.path.isfile(os.path.join(path, file)):
                return False

        for dir in required_dirs:
            if not os.path.isdir(os.path.join(path, dir)):
                return False

        # Validate the inventory.json file
        inventory_path = os.path.join(path, 'inventory.json')
        if not self._validate_inventory(inventory_path):
            return False

        return True

    def _validate_inventory(self, inventory_path):
        """
        Validate the inventory.json file.
        """
        try:
            with open(inventory_path, 'r') as f:
                inventory = json.load(f)

            # Check for required fields in inventory.json
            required_fields = ['id', 'type', 'digestAlgorithm', 'head', 'manifest', 'versions']
            for field in required_fields:
                if field not in inventory:
                    return False

            # Validate the digestAlgorithm
            if inventory['digestAlgorithm'] != 'sha512':
                return False

            # Validate the manifest
            if not isinstance(inventory['manifest'], dict):
                return False

            # Validate the versions
            if not isinstance(inventory['versions'], dict):
                return False

            return True
        except Exception as e:
            return False

def status_str(self, prefix=''):
    """
    सत्यापन लॉग (validation log) का स्ट्रिंग प्रतिनिधित्व लौटाएं, वैकल्पिक प्रीफिक्स के साथ।
    """
    log_str = ""
    for log_entry in self.validation_log:
        log_str += f"{prefix}{log_entry}\n"
    return log_str.strip()

def validate(self, inventory, extract_spec_version=False):
    """
    दिए गए इन्वेंटरी को सत्यापित करें।

    यदि `extract_spec_version` का मान `True` है, तो यह `type` मान को देखकर 
    स्पेसिफिकेशन वर्जन निर्धारित करेगा। यदि `type` मान मौजूद नहीं है या यह 
    मान्य नहीं है, तो अन्य परीक्षण `self.spec_version` में दिए गए वर्जन के 
    आधार पर किए जाएंगे।
    """
    if extract_spec_version:
        if 'type' in inventory:
            spec_version = inventory['type']
            if not self.is_valid_spec_version(spec_version):
                spec_version = self.spec_version
        else:
            spec_version = self.spec_version
    else:
        spec_version = self.spec_version

    # Perform validation based on the determined spec_version
    if spec_version == 'v1':
        return self.validate_v1(inventory)
    elif spec_version == 'v2':
        return self.validate_v2(inventory)
    else:
        raise ValueError(f"Unsupported specification version: {spec_version}")

def is_valid_spec_version(self, spec_version):
    """
    Check if the given specification version is valid.
    """
    return spec_version in ['v1', 'v2']

